1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid when given no live cells", () => {
6	    const result = nextGeneration([]);
7	    expect(result).toEqual([]);
8	  });
9	  it("should kill a single cell with no neighbors (underpopulation)", () => {
10	    const result = nextGeneration([[0, 0]]);
11	    expect(result).toEqual([]);
12	  });
13	  it("should kill two adjacent cells each having only one neighbor (underpopulation)", () => {
14	    const result = nextGeneration([[0, 1], [1, 1]]);
15	    expect(result).toEqual([]);
16	  });
17	  it("should keep a block (2x2 square) unchanged as a still life (survival)", () => {
18	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
19	    const result = nextGeneration(block);
20	    const sort = (cells: [number, number][]) =>
21	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
22	    expect(sort(result)).toEqual(sort(block));
23	  });
24	  it("should bring a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
25	    // L-shape: (0,0), (1,0), (0,1) — dead cell (1,1) has exactly 3 live neighbors
26	    const gen0: [number, number][] = [[0, 0], [1, 0], [0, 1]];
27	    const result = nextGeneration(gen0);
28	    const sort = (cells: [number, number][]) =>
29	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
30	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
31	    expect(sort(result)).toEqual(sort(expected));
32	  });
33	  it.todo("should kill a live cell with more than 3 neighbors (overpopulation)");
34	  it.todo("should evolve a vertical blinker into a horizontal blinker (oscillator)");
35	});
36

1	export function nextGeneration(liveCells: [number, number][]): [number, number][] {
2	  const liveSet = new Set(liveCells.map(([x, y]) => `${x},${y}`));
3	  const neighborCounts = new Map<string, number>();
4	
5	  for (const [x, y] of liveCells) {
6	    for (let dx = -1; dx <= 1; dx++) {
7	      for (let dy = -1; dy <= 1; dy++) {
8	        if (dx === 0 && dy === 0) continue;
9	        const key = `${x + dx},${y + dy}`;
10	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
11	      }
12	    }
13	  }
14	
15	  const result: [number, number][] = [];
16	  for (const [key, count] of neighborCounts) {
17	    if (count === 3 || (count === 2 && liveSet.has(key))) {
18	      const [x, y] = key.split(",").map(Number);
19	      result.push([x, y]);
20	    }
21	  }
22	
23	  return result;
24	}
